import { Component, Element, h, Prop } from '@stencil/core';
import { Target, TextLinkVariants } from '../../models/text-link.types';
import { TextHeaderSizes } from '../wdpr-text-header/wdpr-text-header.model';

@Component({
  tag: 'wdpr-actionable-list-item',
  shadow: true,
})
export class WdprActionableListItem {
  /**
   * Reference to the component's host element.
   */
  @Element() el: HTMLElement;
  /**
   * Unique ID for the list item.
   */
  @Prop() itemId?: string;
  /**
   * The main text to display in the header.
   */
  @Prop() headerLabel!: string;
  /**
   * The pre-header text to display above the main header. Hidden if empty.
   */
  @Prop() preHeader?: string;
  /**
   * The subtext to display below the header. The subtext is hidden if this is empty.
   */
  @Prop() subtextLabel?: string;
  /**
   * icon content for the leading-icon
   */
  @Prop() headerLeadingIcon: string;
  /**
   * set the main Text size
   */
  @Prop() headerSize: TextHeaderSizes;
  /**
   * The main text to display in the link
   */
  @Prop() linkText: string;
  /**
   * The URL the link points to.
   */
  @Prop() linkHref: string;
  /**
   * text icon name to add to the left of the link text
   */
  @Prop() linkLeadingIcon?: string;
  /**
   * text icon name to add at the right of the link text
   */
  @Prop() linkTrailingIcon?: string;
  /**
   * The visual style of the link.
   */
  @Prop() linkVariant?: TextLinkVariants;
  /**
   * Specifies where to open the linked document.
   */
  @Prop() linkTarget?: Target;
  /**
   * Sets an accessible label for the link.
   */
  @Prop() linkA11yLabel: string;
  /**
   * Disables user interaction and applies disabled styling.
   */
  @Prop() linkDisabled: boolean;
  /**
   * Specifies the relationship of the target object to the link object.
   */
  @Prop() linkRel?: string;

  render() {
    return (
      <div class="flex flex-col items-start">
        <wdpr-text-header size={this.headerSize} preHeader={this.preHeader} headerLabel={this.headerLabel} subtextLabel={this.subtextLabel}>
          {this.headerLeadingIcon && <wdpr-icon-library size="medium" icon={this.headerLeadingIcon} slot="leading-icon"></wdpr-icon-library>}
        </wdpr-text-header>
        <wdpr-text-link
          variant={this.linkVariant}
          size="xsmall"
          href={this.linkHref}
          target={this.linkTarget}
          a11yLabel={this.linkA11yLabel}
          disabled={this.linkDisabled}
          rel={this.linkRel}
        >
          {this.linkLeadingIcon && <wdpr-icon-library icon={this.linkLeadingIcon} slot="leading-icon" />}
          {this.linkText && <span>{this.linkText}</span>}
          {this.linkTrailingIcon && <wdpr-icon-library icon={this.linkTrailingIcon} slot="trailing-icon" />}
        </wdpr-text-link>
      </div>
    );
  }
}
